import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"ELM327-emulator","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/obdii-simulators/libraries/elm327-emulator.md","filePath":"obd2/obdii-simulators/libraries/elm327-emulator.md"}'),r={name:"obd2/obdii-simulators/libraries/elm327-emulator.md"};function n(s,e,l,d,c,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="elm327-emulator" tabindex="-1">ELM327-emulator <a class="header-anchor" href="#elm327-emulator" aria-label="Permalink to &quot;ELM327-emulator&quot;">​</a></h1><h2 id="project-description" tabindex="-1">Project description <a class="header-anchor" href="#project-description" aria-label="Permalink to &quot;Project description&quot;">​</a></h2><p><strong>A Python emulator of the ELM327 OBD-II adapter connected to a vehicle supporting multi-ECU simulation.</strong></p><p><em>ELM327-emulator</em> connects client applications to multiple emulated <a href="https://en.wikipedia.org/wiki/Engine_control_unit" target="_blank" rel="noreferrer">ECU</a>s via <a href="https://en.wikipedia.org/wiki/On-board_diagnostics" target="_blank" rel="noreferrer">OBD-II</a> interface through different networking systems, including serial communication (where <a href="https://en.wikipedia.org/wiki/Pseudoterminal" target="_blank" rel="noreferrer">pseudo-terminals</a> are used if supported by the operating systems), or direct interaction with communication devices, or TCP/IP, or Bluetooth. The software simulates an <a href="https://en.wikipedia.org/wiki/ELM327" target="_blank" rel="noreferrer">ELM327</a> adapter connected to a vehicle, includes a command-line interface for extensive monitoring and offers a documented Python development framework to implement ECU emulation objects.</p><p><em>ELM327-emulator</em> is able to support basic ELM327 commands and OBD service requests through stateless request/response method via OBD-II, but can also handle stateful <a href="https://en.wikipedia.org/wiki/Unified_Diagnostic_Services" target="_blank" rel="noreferrer">UDS</a> communication with <a href="https://en.wikipedia.org/wiki/ISO_15765-2" target="_blank" rel="noreferrer">ISO-TP</a> Flow Control and <a href="https://en.wikipedia.org/wiki/Keyword_Protocol_2000" target="_blank" rel="noreferrer">Keyword Protocol 2000</a>, concurrently emulating multiple ECUs. It is designed to be extended via a plugin architecture to allow easy development of specific tasks implementing workflows, including the possibility to simulate anomalies for testing purposes. Many AT commands are supported, as well as some <a href="https://www.obdlink.com/" target="_blank" rel="noreferrer">OBDLink</a> AT/ST <a href="https://www.scantool.net/scantool/downloads/98/stn1100-frpm.pdf" target="_blank" rel="noreferrer">commands</a>.</p><p><em>ELM327-emulator</em> supports different operating systems including Windows, macOS and UNIX/Linux; it is agnostic of the client application and has been tested with <a href="https://github.com/brendan-w/python-OBD" target="_blank" rel="noreferrer">python-OBD</a> as well as with many applications on Windows, Linux and on smartphone devices.</p><p>An internal dictionary (named <em>ObdMessage</em>) allows configuring the emulation, which is currently set to reproduce the message flow generated by more ECUs, including the basic communication of a Toyota Auris Hybrid car (through the <code>scenario car</code> option) and can be easily extended to simulate communication produced by other vehicles or ECUs. In case of more complex interactions (e.g., entering privileged diagnostic sessions and performing reset or flash upload operations), the dictionary can instance tasks, which are implemented through plugins, very simple to be developed by users extending the software. Some example of plugins is already included.</p><p><em>ELM327-emulator</em> also offers a feature that compares the emulation with the direct connection of an OBD-II adapter to allow extending the dictionary by reporting unmatched requests. In addition, it provides an auxiliary scanning tool (<em>obd_dictionary</em>) that builds the ObdMessage dictionary of a specific vehicle by automatically querying all standard OBD service requests one by one (as well as querying additional custom PIDs specified by the user via CSV file); the dictionary can then be used to emulate stateless request/responses of a specific car or ECU.</p><p>Full information and usage details at the <a href="https://github.com/Ircama/ELM327-emulator" target="_blank" rel="noreferrer">ELM327-emulator GitHub repository</a>.</p><h3 id="download-files" tabindex="-1">Download files <a class="header-anchor" href="#download-files" aria-label="Permalink to &quot;Download files&quot;">​</a></h3><p>Download the file for your platform. If you&#39;re not sure which to choose, learn more about <a href="https://packaging.python.org/installing/" target="_blank" rel="noreferrer">installing packages</a>.</p><h4 id="source-distribution" tabindex="-1">Source Distribution <a class="header-anchor" href="#source-distribution" aria-label="Permalink to &quot;Source Distribution&quot;">​</a></h4><h4 id="built-distribution" tabindex="-1">Built Distribution <a class="header-anchor" href="#built-distribution" aria-label="Permalink to &quot;Built Distribution&quot;">​</a></h4>',13)])])}const h=t(r,[["render",n]]);export{p as __pageData,h as default};
